# Deobfuscated Code

Let me work through this step by step.

## Step 1: Resolve the string table

The code uses a rotating string array (`a0_0x111f`) with base64-encoded entries and a lookup function (`a0_0x3e56`). After resolving all the encoded string references, here's the fully deobfuscated code:

```javascript
// Constants
var TAU = 6.283;          // 2π
var PHI = 1.618;          // Golden ratio
var SQRT_HALF = 0.707;    // √(1/2)

// Physics parameters (using corrected names from the blog post)
var params = {
  fieldStrength: 4000,      // Coulomb repulsion magnitude between nodes
  elasticModulus: 0.004,    // Spring stiffness (default for edges)
  convergenceRate: 0.92,    // Velocity damping per tick
  orbitalDecay: 0.0003,     // Center-seeking gravity force
  particleCeiling: 40,      // Max number of sea particles
  streamDecay: 0.04,        // Particle drag/friction
  theta: 0.06               // Camera smoothing factor
};

// === NODES ===
var hub = {
  id: 'hub',
  label: 'Kieleth',
  r: 26,
  x: 400, y: 300,
  vx: 0, vy: 0
};

var alpha = {
  id: 'alpha',
  label: 'Alpha',
  r: 16,
  x: 500, y: 200,
  vx: 0, vy: 0
};

var beta = {
  id: 'beta',
  label: 'Beta',
  r: 16,
  x: 300, y: 400,
  vx: 0, vy: 0
};

var gamma = {
  id: 'gamma',
  label: 'Gamma',
  r: 14,
  x: 250, y: 180,
  vx: 0, vy: 0
};

var delta = {
  id: 'delta',
  label: 'Delta',
  r: 14,
  x: 550, y: 380,
  vx: 0, vy: 0
};

var epsilon = {
  id: 'epsilon',
  label: 'Epsilon',
  r: 12,
  x: 350, y: 150,
  vx: 0, vy: 0
};

var nodes = [hub, alpha, beta, gamma, delta, epsilon];

// === EDGES (springs) ===
// Each edge: { a, b, rest (rest length), k (spring constant) }
var edges = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',  rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// === CAMERA ===
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// === PARTICLES (cosmetic "sea" particles) ===
var particles = [];
var tickCount = 0;

// --- Helper: find node by ID ---
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// --- Physics step ---
function physicsStep() {
  // 1) Coulomb repulsion between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = params.fieldStrength / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Spring attraction along edges
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;

    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || params.elasticModulus) * displacement;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) Per-node: center gravity + damping + position integration
  //    Execution order via switch: "4|0|2|3|5|1"
  for (var n = 0; n < nodes.length; n++) {
    // case 4: center-seeking force (x)
    nodes[n].vx += (400 - nodes[n].x) * params.orbitalDecay;
    // case 0: center-seeking force (y)
    nodes[n].vy += (300 - nodes[n].y) * params.orbitalDecay;
    // case 2: velocity damping (x)
    nodes[n].vx *= params.convergenceRate;
    // case 3: velocity damping (y)
    nodes[n].vy *= params.convergenceRate;
    // case 5: integrate position (x)
    nodes[n].x += nodes[n].vx;
    // case 1: integrate position (y)
    nodes[n].y += nodes[n].vy;
  }
}

// --- Spawn a cosmetic particle ---
function spawnParticle() {
  if (particles.length >= params.particleCeiling) return;

  // Pick a random node as spawn point
  var source = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT_HALF;

  particles.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT_HALF
  });
}

// --- Update particles ---
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];

    // Age check — remove if too old
    if (p.age > p.maxAge) {
      particles.splice(i, 1);
      continue; // (splice + continue via switch ordering)
    }

    // Apply drag
    p.vx *= 1 - params.streamDecay * 0.125;
    p.vy *= 1 - params.streamDecay * 0.125;

    // Integrate position
    p.x += p.vx;
    p.y += p.vy;

    // Increment age
    p.age++;
  }
}

// --- Smooth camera follow ---
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * params.theta;
  camera.y += (cameraTarget.y - camera.y) * params.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * params.theta;
}

// --- Main tick ---
function tick() {
  physicsStep();
  updateParticles();
  updateCamera();

  // Spawn a new particle every 3rd frame
  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

// Run at ~60fps (16ms interval)
setInterval(tick, 16);
```

## What It Does

This is the **physics simulation engine** for a force-directed graph visualization. There is no rendering code here — this is purely the simulation loop. Here's a summary:

### Force-Directed Graph Layout
A classic force-directed graph with **6 nodes** (Kieleth/hub, Alpha, Beta, Gamma, Delta, Epsilon) connected by **8 spring edges** in a hub-and-spoke topology with some cross-links.

Three forces act on nodes each tick:

| Force | Purpose |
|-------|---------|
| **Coulomb repulsion** | All node pairs repel each other inversely proportional to distance² (prevents overlap) |
| **Spring attraction** | Connected nodes are pulled toward each edge's rest length |
| **Center gravity** | Gentle pull toward (400, 300) to keep the graph from drifting away |

Velocities are damped by 0.92× each tick for stability.

### Cosmetic "Sea" Particles
Every 3 frames, a particle spawns at a random node and drifts outward with slight drag. Particles die after 800–2000 frames. This creates an ambient particle-sea aesthetic around the graph.

### Smooth Camera
A camera position lerps toward a target at 6% per tick, enabling smooth panning/zooming (the rendering code that consumes these values isn't included here).

### About the Obfuscation Tricks
1. **String table rotation** — the `a0_0x111f` array is shuffled at startup until a checksum matches
2. **Base64 encoding** — all strings are base64-encoded and decoded at runtime
3. **Control flow flattening** — `while/switch` with string-split ordering like `"4|0|2|3|5|1"` to scramble statement order
4. **Poisoned variable names** — as the blog post explains, the decoded names (`attraction`, `frictionCoeff`, etc.) are deliberately wrong, chosen to be *plausible but misleading* physics terms
